#include <bits/stdc++.h>
using namespace std;

const int N=3e5+5;

struct Stone{
    int x,y,m,p,r;
}a[N];

int n,ans,len;
int b[N],l[600];
long long mx_dist[600];
queue<int> q;

int cal(int x){
    return (x-1)/len+1;
}

long long dist(int ux,int uy,int vx,int vy){
    return 1LL*(ux-vx)*(ux-vx)+1LL*(uy-vy)*(uy-vy);
}

bool cmp1(int x,int y){
    return dist(a[x].x,a[x].y,a[0].x,a[0].y)<dist(a[y].x,a[y].y,a[0].x,a[0].y);
}

bool cmp2(int x,int y){
    return a[x].m<a[y].m;
}

void Find(int x){
    for(int i=1;i<=cal(n);i++){
        if(mx_dist[i]>1LL*a[x].r*a[x].r){
            int top=0,sta[600];
            for(;l[i]<=min(n,i*len);l[i]++){
            	if(a[b[l[i]]].m>a[x].p)
            		break;
                if(dist(a[b[l[i]]].x,a[b[l[i]]].y,a[0].x,a[0].y)<=1LL*a[x].r*a[x].r)
                    q.push(b[l[i]]),ans++;
                else
                    sta[++top]=b[l[i]];
            }
            while(top)
                b[--l[i]]=sta[top--];
            break;
        }else{
            while(l[i]<=min(n,i*len) && a[b[l[i]]].m<=a[x].p)
                q.push(b[l[i]++]),ans++;
        }
    }
}

void solve(){
    len=sqrt(n);
    for(int i=1;i<=n;i++)
        b[i]=i;
    sort(b+1,b+n+1,cmp1);
    for(int i=1;i<=cal(n);i++){
        mx_dist[i]=dist(a[b[min(n,i*len)]].x,a[b[min(n,i*len)]].y,a[0].x,a[0].y);
        l[i]=(i-1)*len+1;
        sort(b+l[i],b+min(n,i*len)+1,cmp2);
    }
    q.push(0);
    while(q.size()){
        int f=q.front();
        //printf("%d\n",f);
        q.pop();
        Find(f);
    }
    printf("%d",ans);
}

int main(){
    scanf("%d%d%d%d%d",&a[0].x,&a[0].y,&a[0].p,&a[0].r,&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d%d%d%d",&a[i].x,&a[i].y,&a[i].m,&a[i].p,&a[i].r);
    solve();
    return 0;
}
